export const LANGS = [
  { key: "ca", label: "Català", flag: "CA" },
  { key: "es", label: "Español", flag: "ES" },
  { key: "en", label: "English", flag: "EN" },
  { key: "de", label: "Deutsch", flag: "DE" },
];

let _lang = "ca";
export function setLangCode(code) { _lang = LANGS.some((l) => l.key === code) ? code : "ca"; }
export function getLang() { return _lang; }

/** Tradueix una clau. Suporta substitució {var}. */
export function t(key, vars) {
  const dict = DICT[_lang] || DICT.ca;
  let s = dict[key];
  if (s == null) s = DICT.ca[key];
  if (s == null) return key;
  if (vars) for (const [k, v] of Object.entries(vars)) s = s.replaceAll(`{${k}}`, v);
  return s;
}

/** Noms de dies i mesos per a la data formatada. */
export function dateParts() { return DATE[_lang] || DATE.ca; }

/** Codi BCP-47 per al reconeixement de veu segons l'idioma actual. */
export function speechLang() { return ({ ca: "ca-ES", es: "es-ES", en: "en-US", de: "de-DE" })[_lang] || "ca-ES"; }

